var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"그라운드 원에 발령된 심각한 뇌우 경보는 며칠 간 지속될 전망입니다.","JPN":"グラウンド・ワンに発令された深刻な雷雨警報は、数日続く見込みです。","ENG":"The severe thunderstorm warning issued for Ground One is anticipated to last several days.","TWN":"針對G1發布的豪雨特報預計將持續好幾天，"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"현재, 관리국은 원인 불명의 기상 현상을 통제하는 데에 최선의 노력을 다하고 있으나…….","JPN":"現在、管理局は原因不明の気象現象を統制するために\\n最善を尽くしていますが……","ENG":"Currently, the Administration is exerting significant effort to control this unidentified weather phenomenon...","TWN":"目前管理局正全力控制不明原因的氣象異常現象，但是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"……라고 하니 다른 도리가 없군요.","JPN":"……ということですので、仕方ありませんね。","ENG":"...So they say, and there's nothing we can do about it.","TWN":"……所以，沒辦法。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회 및 각 교내 모임의 학생 대표 여러분.","JPN":"生徒会および校内会の学年代表の皆様。","ENG":"Student Council and club leaders.","TWN":"學生會和各位學生代表，"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"금일부터 사흘간 개최 예정이었던 아카데미 페스타는 현시간부로 중단하겠습니다.","JPN":"本日より3日間開催予定だったアカデミーフェスタは、\\n現時刻をもって中止いたします。","ENG":"The school festival that was scheduled for three days starting today is canceled, effective immediately.","TWN":"我宣布，從今天起為期三天的學園祭，立刻暫停舉辦。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"따라서 각 대표 여러분은 학급과 동아리로 돌아가셔서 이 사실을 공유해 주시기 바랍니다.","JPN":"従って、各代表の皆様は学級やサークルに戻り、この決定を共有してください。","ENG":"Therefore, each club leader should go back to their respective clubs and share this news with the others.","TWN":"請各位回去向班級和社團傳達這個消息。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 잠깐만요! 회장님!","JPN":"ま、待ってください！　会長！","ENG":"H-hold on! Ms. President!","TWN":"先，先等一下！會長！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L21_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"일 년에 딱 한 번 여는 페스타잖아요! 그런데 개최 당일에 중지 선언이라니요!?","JPN":"一年に一度のフェスタですよ！\\nなのに開催当日に中止宣言をするんですか！？","ENG":"This festival only happens once a year! How can you cancel it last minute last this?!","TWN":"這是一年一次的學園祭欸！怎麼可以在活動當天才喊停！？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"미카의 마음은 잘 알고 있어요. 총학생회장으로서 이런 결정을 내리게 되어 유감입니다.","JPN":"ミカさんの気持ちはよくわかります。\\n生徒会長として、このような決断を下したことはとても残念に思います。","ENG":"I understand your frustration, Mika. And I deliver this news with a heavy heart as the Student President.","TWN":"米卡，我明白你的心情。身為學生會會長，我也很遺憾做出這個決定。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하지만 축제를 즐기려는 마음만큼, 학생분들의 안전도 매우 중요한 문제예요.","JPN":"しかし学園祭を楽しみたい気持ちと同じく、生徒たちの安全もとても重要です。","ENG":"But as much as I want all students to enjoy the festival, the safety of the student body is a crucial matter.","TWN":"只是學園祭的同樂固然重要，但學生們的安全考量也很重要。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"교직원분들 또한 이런 날씨에 페스타를 여는 것을 무척 염려하고 계시고요.","JPN":"教職員の方々も、\\nこのような天気でフェスタを開くことをとても心配しています。","ENG":"The faculty are also concerned about having a festival in this weather.","TWN":"老師們對於要在這種天氣舉辦學園祭也是感到非常擔心。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그렇지만 회장님도 알고 계시잖아요!","JPN":"で、でも会長だってご存知じゃないですか！？","ENG":"B-but Ms. President! You also know!","TWN":"可，可是，會長你也有看到不是嗎！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그동안 여기 있는 모두가 한 마음이 돼서 페스타를 준비해 왔다는 걸!","JPN":"ここにいる皆が一丸となってフェスタを準備してきたということを！","ENG":"Everyone here's been working their butts off to prepare for the festival!","TWN":"這段時間，大家一起努力準備學園祭！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"너도 뭐라고 좀 해 봐, 호진아!","JPN":"マユミちゃんも何か言ってよ！","ENG":"Hey, Hojin! Don't just stand there, say something!","TWN":"你也說幾句話啊，鎬眞！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"으, 으응?","JPN":"う、うん？","ENG":"H-huh?","TWN":"呃，蛤？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그게…… 사실 우리 반은 군고구마 디저트 카페를 개점하려고 했거든.","JPN":"それが……\\n実はうちのクラスは焼き芋のデザートカフェをやることにしていたの。","ENG":"Well... Our class was planning on opening a roasted sweet potato dessert cafe.","TWN":"那個……其實我們班本來是準備要開烤地瓜咖啡廳的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"헤헤, 그런데 고구마 배송이 늦어진다고 해서 축제가 좀 더 미뤄져도 좋을 것 같아.","JPN":"でも雨でさつまいもの配送が遅れると言われて困っていたから、\\n学園祭が遅れてちょっと助かったかも、えヘヘッ。","ENG":"Heh, but it turns out that the delivery for our sweet potatoes got delayed. So I don't mind the festival getting pushed back a little.","TWN":"嘿嘿，但是地瓜來不及在時間內送到，所以延後幾天再辦好像也不錯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"자, 잠깐! 방금 회장님 이야기 못 들었어?","JPN":"ち、ちょっと待ってよ！　さっき会長の話を聞いたでしょ？","ENG":"W-wait! Didn't you hear what she just told us?","TWN":"喂，等等！你沒聽到剛會長說的嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L35_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이대로라면 페스타는 끝장이야. 곧 기말고사라 학교에서도 허락해 주지 않을 거라구.","JPN":"このままだとフェスタはおしまいだよ。\\nもうすぐ期末試験だから、アカデミー側が後日開催なんて許可するはずがないもの。","ENG":"At this rate, there is no festival. Plus, finals are just around the corner, so the school won't allow it.","TWN":"這樣的話學園祭就沒戲唱了，就快要到期末考了，學校也不可能會答應的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"사부, 그게 정말이에요?","JPN":"師匠、それは本当ですか？","ENG":"Master, is that true?","TWN":"師父，米卡說的是真的嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네. 아시다시피 올해는 아카데미에 다사다난한 한 해였죠.","JPN":"はい。\\nご存知のとおり、今年はアカデミーにとって多事多難な一年でした。","ENG":"I'm afraid so. As you all know, it has been a rough year at the Academy.","TWN":"是，你們也知道，今年學院真的是多災多難的一年。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"이번에도 일정이 밀리면 총학생회도 페스타 개최를 보장할 수 없습니다.","JPN":"今回の日程が遅れた場合、総生徒会としてもフェスタの開催は保障できません。","ENG":"If our schedule gets delayed again, the Student Council cannot guarantee that the festival will happen.","TWN":"這次的活動也推遲的話，學生會也無法保證一定能舉辦學園祭。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HOJIN_REBBIT_NULL_NULL","text":{"KOREA":"그, 그럴 수가…….","JPN":"そ、そんな……","ENG":"Th-that can't be...","TWN":"怎，怎麼這樣……"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으아아아! 안 돼! 내가 마술 소품 구하느라고 얼마나 고생했는데!","JPN":"うわあああ！　イヤだよ！\\nマジックの小道具を揃えるために、あれだけ苦労したのに！","ENG":"AGHHHHH! NO! Do you even know the trouble I went through to get my magic supplies?!","TWN":"呃啊啊啊！我好不容易才找到魔術道具的！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HOJIN_REBBIT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이디스 선배도! 그만 자고 평소처럼 기막힌 발명품으로 비 좀 멈추게 해 주세요!","JPN":"イーディス先輩！\\nいい加減起きて、先輩の発明品であの雨を止めてくださいよ！","ENG":"Edith! Stop napping and come up with some cool invention that will stop the rain!","TWN":"伊蒂絲前輩你也是！ 別再睡了！\\n趕快和平時一樣，用你厲害的發明讓雨停下來啦！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"음냐. 음냐.","JPN":"ムニャムニャ……","ENG":"Zzz... Zzz...","TWN":"嗯嗯嗯嗯。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"에잇! 이렇게 된 거 선배도 눈이 번쩍 뜨일 만한 무대 마술을……!","JPN":"ふん！\\nこうなったら先輩の目がパッと覚めるような舞台用マジックを……！","ENG":"Ugh! I need to perform some incredible magic that will make her eyes open wide...!","TWN":"討厭！這樣的話，我就不能施展讓前輩眼睛為之一亮的魔……！"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"AI_SCHOOL_NULL_NULL","text":{"KOREA":"식별되지 않은 위험 개체의 접근을 감지. 자동 방어 시스템을 전개합니다.","JPN":"識別されていない危険個体の接近を感知。自動防御システムを展開します。","ENG":"Unidentified threat detected. Initializing auto-defense system...","TWN":"感應到無法識別的危險個體，啟動自動防禦系統。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_33"},{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"얼레?","JPN":"あれ？","ENG":"Huh?","TWN":"是怎樣？"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"학생회가 부끄러운 모습을 보이고 말았군요.","JPN":"生徒会がお恥ずかしいところを見せてしまいましたね。","ENG":"I am sorry on behalf of the Student Council.","TWN":"真是不好意思，讓你看到學生會這樣吵吵鬧鬧的。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"본업으로 바쁜 와중에도 페스타에 참석해 주셨는데 면목이 없네요.","JPN":"本業でお忙しい中フェスタに参加していただいたのに、面目ございません。","ENG":"You have come for the festival amidst your busy schedule, but to cancel it like this.","TWN":"你的本業那麼忙，還特地撥空來參加學園祭，我真是沒臉見你。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도 일단 아카데미 학생인걸. 너무 신경 쓰지 마.","JPN":"私も一応アカデミーの生徒だもの。あまり気にしないで。","ENG":"I'm also a student of the Academy. Don't worry too much about me.","TWN":"畢竟我也算是學院的學生，不用這麼客氣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"갑자기 날씨가 이렇게 될 줄 누가 알았겠어.","JPN":"天気が急にこんなことになるなんて思わなかったね。","ENG":"Who would've known that the weather would turn out like this, right?","TWN":"誰知道天氣會突然變成這樣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"그렇죠. 하지만 헛된 발걸음을 하시게 만든 것 같아 마음이 몹시 불편하군요.","JPN":"そうですね。無駄足を踏ませてしまい、とても心苦しいです。","ENG":"Yes. But I feel uncomfortable for making you come all this way for nothing.","TWN":"是啊，但讓你白跑一趟，我心裡還是很過意不去。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"잘 들으세요, 미나 양. 회사 생활은 보기보다 힘들답니다.","JPN":"よく聞いてください、ミナさん。社会人とは思ってるよりもつらいものです。","ENG":"Listen carefully, Mina. Working at a company is harder than it looks.","TWN":"米娜，你聽我說，職場生活比你想像中還要辛苦，"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L15_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러니까 쉴 수 있는 명분이 있다면 무조건 쉬는 게 좋아요.","JPN":"だから休める名分があるのなら、とりあえず休んだほうがいいですよ。","ENG":"So when you have an excuse to take a break, you should take it, no matter what.","TWN":"有機會能休息就一定要休。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보면 부사장님은 미나 양의 학업과 관련된 부분에선 묘하게 약해지시던데요?","JPN":"そういえば副社長もミナさんの学業のことになると、少し緩くなっていましたね？","ENG":"Come to think of it, Vice President is oddly soft when it comes to your studies, right, Mina?","TWN":"這麼說來，副總最近好像沒那麼關心你的課業。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"그 부분을 공략하면 굳이 아까운 휴가를 쓰지 않고도 출장 처리만으로……","JPN":"その辺を突けば、わざわざ有休を使わなくても出張申請だけで……","ENG":"If you use that to your advantage, you might be able to save your leave days and just report them as business trips...","TWN":"我們可以利用這一點，就可以把珍貴的特休留起來，改成用出差的方式……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아하하…… 그러니까 그건 신경 쓰지 말래도.","JPN":"アハハ……だからそんなの気にしなくていいって。","ENG":"Ah hah hah... Really, don't worry about that.","TWN":"哈哈哈……就說不用這麼客氣。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L23_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"네, 들어오세요.","JPN":"はい、どうぞ。","ENG":"Yes, come in.","TWN":"是，請進。"},"stage":{"bg":"MEETING_ROOM","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"뭐야, 너희들! 언제까지 이 몸을 기다리게 할 셈이야!?","JPN":"なんなの、あんたたち！　いつまでこの私を待たせる気！？","ENG":"What are you guys even doing?! How much longer are you going to make me wait?!","TWN":"你們在搞什麼！是要讓我等到什麼時候！？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_TADA"},{"id":"L29_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"나이엘 학생, 그 복장은 뭐죠?","JPN":"ナイエルさん、その服装はどうしたのですか？","ENG":"Naielle, what are you wearing?","TWN":"奈爾，你這身打扮是？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어라? 나이엘, 너 그 옷차림은……?","JPN":"あれ？　ナイエル、その格好は……？","ENG":"Huh? Naielle, your outfit...","TWN":"哇賽？奈爾，你的衣服……？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L31_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"혹시 코스프레 동아리의 차기 회장 콘테스트에 참가하려고?","JPN":"もしかしてコスプレサークルの次期部長コンテストに参加するの？","ENG":"Are you participating in the next student president cosplay contest hosted by the cosplay club?","TWN":"你是要競選下一任Cosplay社團的社長嗎？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"차기 회장 콘테스트라고요? 그런 콘테스트는 허가한 적이 없을 텐데요?","JPN":"次期部長コンテストですか？\\nそのようなコンテストを許可した覚えはありませんが。","ENG":"Next student president contest? I don't recall giving permission for such a contest.","TWN":"競選下一任社長？我應該沒有答應可以舉辦吧？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"꽤 그럴싸하네. 대단하다.","JPN":"なんかそれっぽいね。すごい。","ENG":"It looks pretty good. Impressive.","TWN":"看起來，不錯喔。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그, 그래! 체육대회 때는 웬 방해꾼이 끼어들어서 원래 실력을 발휘 못했던 것뿐이야!","JPN":"そ、そうよ！\\n運動会の時は邪魔者が入ったせいで本来の力を発揮できなかっただけ！","ENG":"Y-yeah! Someone interrupted me during the field day, so I couldn't show off all of my skills!","TWN":"當，當然！上次運動會不知道是哪個\\n不長眼的冒出來搗亂，害我沒辦法發揮實力！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"이번 페스타는 달라! 반드시 모든 콘테스트에서 1등을 차지하고 말 거라구!!","JPN":"今回のフェスタは違う！　絶対にすべてのコンテストで1位を取ってやる！！","ENG":"But not this festival! I'll make sure I get first place in every contest!!","TWN":"這次學園祭可不一樣！我一定要在每個比賽都拿第一！！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그러니까 1등을 위해서라면 이딴 파렴치한 옷도 얼마든지 입어 줄 수 있단 말이지!","JPN":"だから1位のためなら、\\nこんな破廉恥な服だっていくらでも着れるってことよ！","ENG":"So, I'll do whatever it takes! Even if it means wearing this humiliating costume!","TWN":"只要能拿下第一，穿這種恥度大開的衣服也只是小Case啦。"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"파렴치?","JPN":"破廉恥？","ENG":"Humiliating?","TWN":"恥度大開？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"크, 크흠!! 아무튼!!","JPN":"こ、こほん！！　とにかく！！","ENG":"A-ahem!! Anyway!!","TWN":"咳，咳咳！總之！！"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"아카데미 페스타는 대체 언제 시작하는 건데?","JPN":"アカデミーフェスタはいつ始まるのよ！？","ENG":"So when does the Academy festival start?","TWN":"學園祭到底什麼時候開始？"},"stage":{"bg":"MEETING_ROOM","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"인정 못해……!! 인정 못해, 인정 못한다구우우우우!!","JPN":"認めない……！！　中止だなんて、絶対に認められないっての！！","ENG":"I refuse to accept this...!! This is unacceptable! UNACCEPTABLE!!","TWN":"我不接受……！！我不答應，絕不同意！！！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"기껏 용기내서 입었는데! 차기 회장에 걸맞은 완벽한 포즈도 준비했는데!","JPN":"せっかく勇気を出して着たのに！\\n次期会長にふさわしい完璧なポーズも練習したのに！","ENG":"I had to muster up all my courage to wear this! I even practiced the perfect pose!","TWN":"我好不容易才鼓起勇氣穿上去的！我連適合下一任社長的Pose都想好咧！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"페스타가 중단되다니 말도 안 돼!!","JPN":"フェスタが中止だなんてありえない！！","ENG":"But the festival being canceled? This is ridiculous!","TWN":"竟然要停辦學園祭，這怎麼可以！！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"진정해, 나이엘. 페스타가 올해만 열리는 것도 아니잖아.","JPN":"落ち着いて、ナイエル。フェスタは今年だけ開かれるってわけでもないし。","ENG":"Calm down, Naielle. It's not like this is the only year the festival's gonna open.","TWN":"奈爾，你冷靜點，學園祭又不是只有今年才有。"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"시끄러워, 편입생! 네가 그러고도 아카데미 학생이냐!?","JPN":"うるさい、編入生！　あんたはそんなことでアカデミーの生徒を名乗れるの！？","ENG":"Shut it, transfer student! And you call yourself a student of the Academy?!","TWN":"你閉嘴，轉學生！你這樣還敢說你是學院的學生嗎！？"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L3_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"아카데미 학생이라면 운동회와 페스타에 목숨을 거는 게 상식이라구!","JPN":"アカデミーの生徒なら運動会やフェスタに命をかけるのが常識でしょ！","ENG":"It's common sense for all Academy students to devote their lives to field days and festivals!","TWN":"身為學院的學生，為運動會和學園祭拼命是基本常識！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"좋아! 이렇게 된 이상 나 혼자서라도 전교생에게 페스타 재개 동의서를 받아내 주겠어!","JPN":"よし！　こうなった以上、\\n私一人だけでも全校生からフェスタ再開嘆願書を集めてやる！","ENG":"Fine! Then I'll go around the entire school gathering petitions to restart the festival!","TWN":"好吧！既然如此，那我要去找全校的學生連署，要求重啟學園祭！"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하하, 아무리 그래도 이런 날씨에는 조금…….","JPN":"ハハ、いくら何でもこんな天気じゃね……","ENG":"Ha ha, but even if you did, look at the weath–","TWN":"哈哈，就算連署成功，但天氣這麼糟……"},"stage":{"bg":"CORRIDOR_05","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나이엘, 방금 뭔가 오싹한 기분 안 들었어?","JPN":"ナイエル、今なんかゾッとする感じがしなかった？","ENG":"Naielle, did you also feel a chill down your spine?","TWN":"奈爾，你剛有感覺到什麼不對勁嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"뭐? 그러고 보니 확실히 허리 밑이 조금 오싹한 것 같기도 하고…… 엣츄!","JPN":"え？　そういえば確かに\\n下の方からゾクゾクとした感覚がするような……はくしょん！","ENG":"Huh? Now that you mention it, I do feel a bit chilly beneath my waist... Achoo!","TWN":"什麼東東？這麼說來，我的腰好像真的有點不對勁……哈啾！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"또야…….","JPN":"またか……","ENG":"This again...?","TWN":"又來了……"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그런데…… 지금까지 느꼈던 침식파와는 어딘가 달라.","JPN":"でも……これまで感じた侵食波とは何かが違う。","ENG":"But still... This one feels different from the Corruption ray we're used to.","TWN":"不過……這次的侵蝕波和之前的好像不太一樣。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나이엘, 잠깐 기다려. 밖에 무슨 일이 있나 보고 올게.","JPN":"ナイエル、ちょっと待ってて。\\n外で何が起きているか見てくる。","ENG":"Naielle, wait here. I'll go see if anything's happening outside.","TWN":"奈爾，你等我一下，我去外面看看發生什麼事。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"잠깐, 야! 비가 저렇게 쏟아지는데 어딜 가려는 거야?!","JPN":"待ちなさいよ！　こんなどしゃぶりの中どこに行くの！？","ENG":"Hey, wait! Where do you think you're going?! It's pouring out there!","TWN":"等一下，喂！外面雨下得那麼大，你是要去哪裡？！"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아마도 이 근처인 것 같은데…….","JPN":"おそらくこの近くのはず……","ENG":"It should be around here...","TWN":"應該就在附近啊……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"헤엑……! 헥……! 좀 천천히 가!","JPN":"はあ……！　はあっ……！\\nちょっと、ゆっくり歩いてよ！","ENG":"*Huff...!* *Huff...!* Wait up!","TWN":"呼呼……！呼……！你慢一點啦！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어라? 왜 따라왔어, 나이엘?","JPN":"あれ？　なんでついて来たの、ナイエル？","ENG":"Huh? Why'd you follow me, Naielle?","TWN":"嗯？奈爾？你怎麼跟來了？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"흐, 흐흥. 그야 침식체가 나타난 거라면 당연히 이 나이엘 님이 해치워야 하니까.","JPN":"ふ、ふん！　そりゃあアカデミーに侵食体が現れたなら、\\nこのナイエル様がやっつけないといけないからよ！","ENG":"Heh heh. Well, if it's a C.O., then I should be the one to defeat it.","TWN":"哼哼，要是有侵蝕體的話，當然要由奈爾我來解決囉。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"알겠어, 편입생?! 나보다 더 활약하는 건 용납 못한단 말이야!","JPN":"編入生、わかった！？　私より活躍するのは許さないから！","ENG":"You got that, transfer student?! I won't tolerate you outshining me!","TWN":"知道沒，轉學生？！我絕對不允許有人比我出風頭！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"끼야악! 뭐야, 이거! 엄청 찌릿거려!","JPN":"キャーッ！　なにこれ！　めちゃくちゃビリビリする！","ENG":"Kyaah! What was that?! It feels like pins and needles!","TWN":"啊啊啊！搞什麼！好痠麻！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"아, 아니지. 천하의 나이엘 님이 고작 이 정도의 침식파에 겁먹을 리가……","JPN":"い、いや違うわよ。\\n天下のナイエル様がたかがこの程度の侵食波を恐れると思ったら……","ENG":"W-wait. The great Naielle is not afraid of some stupid Corruption ray...","TWN":"不，不是，我可是天下無敵的奈爾，才不會被這區區的侵蝕波給嚇到……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나이엘, 하늘을 봐!","JPN":"ナイエル、空を見て！","ENG":"Naielle! Look at the sky!","TWN":"奈爾，你看天空！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"하늘? 하늘은 왜?","JPN":"空？　空がどうしたの？","ENG":"Look up? At the sky?","TWN":"天空？看天空幹嘛？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"히에엑! 하늘에 구멍이 뚫렸잖아!?","JPN":"ひいぃーっ！　空に穴が空いている！？","ENG":"Yikes! Why's there a hole in the sky?!","TWN":"欸欸欸！天空破洞咧！？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리가 느낀 침식파는 아마 저 균열에서 흘러나온 것 같아.","JPN":"私たちが感じた侵食波は、おそらくあの亀裂から流れてきたみたい。","ENG":"I think the Corruption ray we felt is seeping out from that dimensional rift.","TWN":"我們感受到的侵蝕波應該就是從那個裂縫裡來的。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그럼 날씨가 이 꼴인 것도 저 구멍 때문이란 말이야?","JPN":"じゃあ天気がこの有様なのも、あの穴のせいってこと？","ENG":"Are you saying that the weather's like this because of that hole?","TWN":"那天氣會這樣也是因為那個洞嗎？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나도 처음 보는 거라……. 아마 그렇지 않을까?","JPN":"私も初めてみるから確証はないけど……多分そうじゃない？","ENG":"I've never seen anything like it before... So... Maybe?","TWN":"我也是第一次看到……應該不無可能吧？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"흥, 좋아. 저걸 없애면 페스타를 다시 열 수도 있단 말이지.","JPN":"ふん、いいわ。あれを消したらフェスタが再開するってことね。","ENG":"Hmph, all right. So the festival will reopen if that hole's gone, right?","TWN":"哼，很好，只要把那個洞補起來，應該就可以重啟學園祭吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그렇다면 여기서는 이 나이엘 님이…….","JPN":"ならここで、このナイエル様が……","ENG":"Then I guess it's time for me, the great Naielle, to–","TWN":"那奈爾我在此……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"두 분, 교실에 계시지 않고 여기서 뭘 하시는 거죠?","JPN":"お二人とも、教室におらずにここで何をしているのですか？","ENG":"You two. Why aren't you in your classes?","TWN":"你們二個為什麼不待在教室裡，在這裡做什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"히익! 학생회장!?","JPN":"ひいっ！　生徒会長！？","ENG":"Eek! It's the Student President!","TWN":"唔唔！會長！？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"다이브 실습 때가 떠오르네요, 나이엘 양. 이번에는 또 무슨 일인가요?","JPN":"ダイブ実習の時を思い出しますね、ナイエルさん。\\n今度は何事でしょう？","ENG":"This reminds me of Dive training day, Naielle. What are you up to this time?","TWN":"我想起躍入實習時發生的事呢。奈爾，你這次又想做什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"이번에는 내가 나가자고 한 게 아니야! 편입생이 멋대로……!","JPN":"今回は私が言い出したんじゃないわよ！　編入生が勝手に……！","ENG":"It wasn't me! She's the one who...!","TWN":"這次不是我帶頭的喔！是轉學生她……！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"회장, 지금 그런 얘기하고 있을 때가 아니야.","JPN":"会長、今そんなことを話している場合じゃない。","ENG":"Yen, now's not the time for that.","TWN":"會長，現在重點不是這個。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하늘을 봐.","JPN":"空を見て。","ENG":"Look at the sky.","TWN":"你看天空。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하늘?","JPN":"空、ですか？","ENG":"The sky?","TWN":"天空？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"하늘이…… 붉게 빛나고 있군요.","JPN":"空が……赤く光っていますね。","ENG":"It's... glimmering in a crimson hue.","TWN":"天空……發出紅光。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그, 그래! 저 구멍 때문에 날씨가 나빠진 게 틀림없어!","JPN":"そ、そうよ！\\nあの穴のせいで天気が悪くなったに違いないわ！","ENG":"Y-yeah! I'm sure that the weather's like this because of that hole!","TWN":"對，對啊！一定就是因為那個洞，氣候才會異常啦！"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"그러니까 저것만 없애면 아카데미 페스타를 다시 열 수 있을지도 몰라!","JPN":"だからあれさえ消せば、\\nアカデミーフェスタを再開することができる！","ENG":"So if we can get rid of that, we might be able to reopen the Academy festival!","TWN":"所以只要把那個洞補起來，應該就可以重啟學園祭吧！？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"잘은 모르겠지만 급성 침식 현상으로 추측되는군요.","JPN":"断言はできませんが、急性侵食現象と推測されますね。","ENG":"I'm not sure, but I believe this to be an acute Counterside Effect.","TWN":"我也不太清楚，但我猜應該是急性侵蝕現象。"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"알겠습니다. 관리국에는 제가…….","JPN":"了解しました。管理局には私から……","ENG":"Very well. I'll call the Adminis–","TWN":"好吧，管理局那邊就由我……"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐만, 저 균열 왠지 아까보다 커진 것 같지 않아?","JPN":"待って。あの亀裂、さっきより大きくなってない？","ENG":"Wait! The rift... Doesn't it seem bigger than before?","TWN":"等等，你們不覺得縫隙似乎變得比剛才還要大嗎？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"무슨 소리 하는 거야? 아까랑 뭐가……?","JPN":"何を言ってるの？　さっきと何が……","ENG":"What are you talking about? It looks pretty same to m–","TWN":"你在胡說八道什麼？和剛才明明就……？"},"stage":{"bg":"SKY_RED","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"꺄아악!?","JPN":"きゃああっ！！","ENG":"Eeek!!","TWN":"啊啊啊！？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_CHANGE","text":{"KOREA":"둘 다 봤어? 방금 저 안쪽에서 뭔가 번쩍했다구!","JPN":"今の見た？　あの奥で何かがピカッて光った！","ENG":"Did you see that? Something flashed from within!","TWN":"你們有看到嗎？剛才那裡面好像有什麼東西閃過去！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_CHANGE","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이쪽으로 날아온다! 다들 피해!","JPN":"こっちに飛んでくる！　みんな避けて！","ENG":"It's coming this way! Duck!","TWN":"朝這邊來了！大家小心！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_RAIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_ELECTRIC_04"}]`);export{e as default};